    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type  # 'number', 'binop', 'unary'
        self.value = value  # for numbers
        self.op = op  # for operators
        self.left = left  # for binop
        self.right = right  # for binop
        self.operand = operand  # for unary


def parse(expression):
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    # Remove whitespace
    expression = expression.replace(" ", "")

    # Tokenizer
    def tokenize(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isdigit() or expr[i] == ".":
                # Parse number
                num = ""
                while i < len(expr) and (expr[i].isdigit() or expr[i] == "."):
                    num += expr[i]
                    i += 1
                tokens.append(("NUMBER", float(num)))
            elif expr[i] in "+-*/()":
                tokens.append(("OPERATOR", expr[i]))
                i += 1
            else:
                raise ValueError(f"Invalid character: {expr[i]}")
        return tokens

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Invalid expression")

    # Parser
    def parse_expression(tokens, pos):
        return parse_add_sub(tokens, pos)

    def parse_add_sub(tokens, pos):
        left, pos = parse_mul_div(tokens, pos)

        while pos < len(tokens) and tokens[pos][1] in ["+", "-"]:
            op = tokens[pos][1]
            pos += 1
            right, pos = parse_mul_div(tokens, pos)
            left = ASTNode("binop", op=op, left=left, right=right)

        return left, pos

    def parse_mul_div(tokens, pos):
        left, pos = parse_unary(tokens, pos)

        while pos < len(tokens) and tokens[pos][1] in ["*", "/"]:
            op = tokens[pos][1]
            pos += 1
            right, pos = parse_unary(tokens, pos)
            left = ASTNode("binop", op=op, left=left, right=right)

        return left, pos

    def parse_unary(tokens, pos):
        if pos < len(tokens) and tokens[pos][1] == "-":
            pos += 1
            operand, pos = parse_factor(tokens, pos)
            return ASTNode("unary", op="-", operand=operand), pos
        else:
            return parse_factor(tokens, pos)

    def parse_factor(tokens, pos):
        if pos >= len(tokens):
            raise ValueError("Unexpected end of expression")

        token_type, token_value = tokens[pos]

        if token_type == "NUMBER":
            pos += 1
            return ASTNode("number", value=token_value), pos
        elif token_value == "(":
            pos += 1
            expr, pos = parse_expression(tokens, pos)
            if pos >= len(tokens) or tokens[pos][1] != ")":
                raise ValueError("Unmatched parenthesis")
            pos += 1
            return expr, pos
        else:
            raise ValueError(f"Unexpected token: {token_value}")

    # Parse the expression
    root, pos = parse_expression(tokens, 0)

    # Ensure we consumed all tokens
    if pos != len(tokens):
        raise ValueError("Invalid expression")

    return root


def evaluate(node):
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
